func:
// ตั้งค่า global ตอน deploy: header + path
global.set("FALL_SENSOR_LAB_CSV_HEADER", "session_id,trial_id,activity_label,expected_type,timestamp_ms,type,state,ax_g,ay_g,az_g,gx_dps,gy_dps,gz_dps,svm_raw_g,svm_filtered_g,pitch_deg,roll_deg,pitch_before_deg,roll_before_deg,pitch_after_deg,roll_after_deg,pitch_delta_deg,roll_delta_deg,posture_delta_deg,impact_threshold_g,posture_threshold_deg,stabilize_ms,decision,note");
flow.set("runsDir", env.get("SENSOR_LAB_RUNS_DIR")
    || "firmware/esp32/fall_detection_sensor_lab/runs");
flow.set("recording", false);
node.status({fill:"green",shape:"dot",text:"globals ready"});
return null;

// ตั้ง metadata + เปิดบันทึก + เขียน header
// #2 กัน trial ไม่มี metadata : ปกติ fn_activity บน Dashboard ตั้ง trialMeta ให้แล้ว
var fmeta = flow.get("trialMeta");
var hasMsgMeta = msg.trialId && msg.activityLabel;
if (!fmeta && !hasMsgMeta) {
    node.status({fill:"red",shape:"ring",text:"กดปุ่ม Activity บน Dashboard ก่อนเริ่ม Trial"});
    return null;
}

var meta = {
    sessionId: (fmeta && fmeta.sessionId) || env.get("SENSOR_LAB_SESSION_ID") || "-",
    trialId: msg.trialId || (fmeta && fmeta.trialId) || "T01",
    activityLabel: msg.activityLabel || (fmeta && fmeta.activityLabel) || "standing_still",
    expectedType: msg.expectedType || (fmeta && fmeta.expectedType) || "non_fall",
    note: msg.note || (fmeta && fmeta.note) || ""
};
flow.set("trialMeta", meta);
flow.set("recording", true);

var sid = meta.sessionId, tid = meta.trialId, act = meta.activityLabel;
var file = flow.get("runsDir") + "/" + sid + "/raw/" + sid + "_" + tid + "_" + act + ".csv";

// #1 กัน header ซ้ำกลางไฟล์ : ถ้า trial นี้เคย Start แล้วใน session นี้ ไม่เขียน header อีก
var started = flow.get("startedFiles") || {};
if (started[file]) {
    node.status({fill:"yellow",shape:"dot",text:"resume "+tid+" (header มีแล้ว)"});
    return null;
}
started[file] = true;
flow.set("startedFiles", started);

var header = global.get("FALL_SENSOR_LAB_CSV_HEADER");
node.status({fill:"blue",shape:"dot",text:"REC "+sid+"_"+tid+" "+act});

// ส่ง header ออกไป init ไฟล์ (file node createDir=true จะสร้างโฟลเดอร์ให้)
return [{ filename: file, payload: header, _initHeader: true }];

// Stop pressed: แสดงสถานะอย่างเดียว การตัดสิน/มิวเทตทำที่ fn_trialdone
// (กัน race: ไม่แก้ recording/countdown ที่นี่)
var meta = flow.get("trialMeta") || {};
node.status({fill:"grey",shape:"ring",text:"stop pressed "+(meta.trialId||"")});
return null;

// รับ payload จาก device/+/lab/imu แล้วแปลงเป็น CSV row
// เก็บเฉพาะช่วงที่ Start Trial แล้ว (flow.recording === true)
if (flow.get("recording") !== true) {
    node.status({fill:"grey",shape:"ring",text:"idle (no trial)"});
    return null;
}

var p = msg.payload;
if (typeof p === "string") {
    try { p = JSON.parse(p); } catch (e) { return null; }
}

var meta = flow.get("trialMeta") || {};
var serial = (msg.topic || "").split("/")[1] || "unknown";

function f(v){ return (v === undefined || v === null) ? "" : v; }

var cols = [
    f(meta.sessionId), f(meta.trialId), f(meta.activityLabel), f(meta.expectedType),
    f(p.timestamp), f(p.type), f(p.state),
    f(p.ax), f(p.ay), f(p.az), f(p.gx), f(p.gy), f(p.gz),
    f(p.svmRaw), f(p.svmFiltered),
    f(p.pitch), f(p.roll),
    f(p.pitchBefore), f(p.rollBefore), f(p.pitchAfter), f(p.rollAfter),
    f(p.pitchDelta), f(p.rollDelta), f(p.postureDelta),
    f(p.impactThreshold), f(p.postureThreshold), f(p.stabilizeMs),
    f(p.decision), f(meta.note)
];

var sid = meta.sessionId || "S00";
var tid = meta.trialId || "T00";
var act = meta.activityLabel || "unknown";
msg.filename = flow.get("runsDir") + "/" + sid + "/raw/" + sid + "_" + tid + "_" + act + ".csv";
msg.payload = cols.join(",");
node.status({fill:"green",shape:"dot",text:sid+"_"+tid+" "+f(p.type)});
return msg;

var raw = '';
if (typeof msg.payload === 'object' && msg.payload.sessionId !== undefined) {
    raw = msg.payload.sessionId;
} else if (typeof msg.payload === 'string') {
    raw = msg.payload;
}
raw = ('' + raw).trim();
if (!raw) { node.status({fill:'red',shape:'ring',text:'กรอก Session ID'}); return null; }

var m = raw.match(/^[Ss]?0*(\d+)$/);
if (!m) {
    node.status({fill:'red',shape:'ring',text:'ไม่อนุญาตตัวอักษรพิเศษ (ใช้ S ตามด้วยตัวเลขเท่านั้น)'});
    return null;
}

var n = parseInt(m[1], 10);
var sid = 'S' + ('' + n).padStart(2, '0');

var nextSeq = 1;
var completedActs = [];
try {
    var baseDir = '/data/runs';
    var sessionDir = pathMod.join(baseDir, sid);
    var rawDir = pathMod.join(sessionDir, 'raw');
    var selectedDir = pathMod.join(sessionDir, 'selected');
    var notesFile = pathMod.join(sessionDir, 'session_notes.md');

    if (!fsMod.existsSync(rawDir)) {
        fsMod.mkdirSync(rawDir, { recursive: true });
        node.warn('Created directory: ' + rawDir);
    } else {
        var files = fsMod.readdirSync(rawDir);
        files.forEach(function(f) {
            var match = f.match(/_T(\d+)_([^.]+)\.csv$/);
            if (match) {
                var tSeq = parseInt(match[1], 10);
                if (tSeq >= nextSeq) {
                    nextSeq = tSeq + 1;
                }
                var actLabel = match[2];
                if (completedActs.indexOf(actLabel) === -1) {
                    completedActs.push(actLabel);
                }
            }
        });
    }

    if (!fsMod.existsSync(selectedDir)) {
        fsMod.mkdirSync(selectedDir, { recursive: true });
        node.warn('Created directory: ' + selectedDir);
    }

    if (!fsMod.existsSync(notesFile)) {
        var notesContent = "# Session " + sid + " Notes\n\nใช้จดปัญหาและข้อสังเกตระหว่างการเก็บข้อมูล\n\n## ตารางบันทึกปัญหา\n\n| Date | Trial | Activity | Note | Action |\n|---|---|---|---|---|\n| - | - | - | - | - |\n\n## Checklist หลังเก็บข้อมูล\n\n| รายการ | สถานะ |\n|---|---|\n| CSV ถูกสร้างใน raw/ | [ ] |\n| คัดเลือกไฟล์ไปที่ selected/ | [ ] |\n| มี note ถ้าพบปัญหา | [ ] |\n| ถ่ายภาพท่าทดสอบแล้ว | [ ] |\n";
        fsMod.writeFileSync(notesFile, notesContent, 'utf8');
        node.warn('Created notes file: ' + notesFile);
    }
} catch(err) {
    node.error('Failed to create/scan directory: ' + err.toString());
}

flow.set('sessionId', sid);
flow.set('trialSeq', nextSeq - 1);
flow.set('completedActivities', completedActs);

var meta = flow.get('trialMeta') || {};
meta.sessionId = sid;
flow.set('trialMeta', meta);

var nextId = 'T' + ('' + nextSeq).padStart(2, '0');
node.status({fill:'green', shape:'dot', text:'session ' + sid + ' (' + completedActs.length + ' acts)'});

var warnMsg = completedActs.length > 0 ? " | ทำแล้ว " + completedActs.length + " ท่า" : "";

return [
    { payload: 'บันทึก Session ' + sid + ' สำเร็จแล้ว' + warnMsg },
    { payload: { sessionId: sid, trialId: nextId, activityLabel: '-', expectedType: '-', recordingState: (flow.get('recording') === true ? 'recording' : 'ready') } },
    { payload: 'scan' },
    { payload: 'reset' }
];

var FALL = {side_fall_left:1, side_fall_right:1, forward_fall:1, backward_fall:1};
var act = msg.payload;

if (!act) { 
    node.status({fill:"red",shape:"ring",text:"no activity"}); 
    return null; 
}

var completedActs = flow.get("completedActivities") || [];
if (completedActs.indexOf(act) !== -1) {
    node.status({fill:"red",shape:"ring",text:"ทำไปแล้ว"});
    return [null, null, {payload: "⚠️ ท่า " + act + " ได้ถูกบันทึกไปแล้วใน Session นี้! (เปลี่ยนท่าอื่น หรือสร้าง Session ใหม่)"}];
}

if (flow.get("recording") === true || flow.get("countdownActive") === true) {
    node.status({fill:"red",shape:"ring",text:"trial กำลังทำงาน"});
    return [null, null, {payload: "กำลังบันทึกข้อมูลอยู่ กรุณากด Stop Trial ก่อนเริ่มรอบใหม่"}];
}

var sid = flow.get("sessionId") || env.get("SENSOR_LAB_SESSION_ID") || "-";
if (!sid || sid === "-") {
    node.status({fill:"red",shape:"ring",text:"กรุณากรอก Session ID"});
    return [null, null, {payload: "กรุณาระบุ Session ID และกดบันทึกก่อนเริ่มทดสอบ!"}];
}

var lab = flow.get("lastLabMsgTs");
var now = Date.now();
if (!lab || (now - lab > 10000)) {
    node.status({fill:"red",shape:"ring",text:"Device Offline - Cannot start"});
    return [null, null, {payload: "❌ อุปกรณ์ออฟไลน์! ไม่พบสัญญาณจากเซนเซอร์ กรุณาตรวจสอบให้แน่ใจว่า Device เชื่อมต่ออยู่ก่อนกดปุ่ม"}];
}

var seq = (flow.get("trialSeq") || 0) + 1;
var tid = "T" + ("" + seq).padStart(2, "0");
var meta = {
    sessionId: sid,
    trialId: tid,
    activityLabel: act,
    expectedType: FALL[act] ? "fall" : "non_fall",
    note: ""
};
flow.set("trialMeta", meta);
flow.set("pendingSeq", seq);
node.status({fill:"yellow",shape:"dot",text:tid+" "+act+" -> countdown"});

return [
    {trialId: tid, activityLabel: meta.activityLabel, expectedType: meta.expectedType, note: ""},
    {payload:{sessionId:sid, trialId:tid, activityLabel:meta.activityLabel, expectedType:meta.expectedType, recordingState:"countdown"}},
    null
];

// นับถอยหลัง 10 วินาทีก่อนเริ่ม recording (ไม่มีเสียงใน dashboard)
var startMeta = {trialId: msg.trialId, activityLabel: msg.activityLabel, expectedType: msg.expectedType, note: msg.note || ""};
var sid = flow.get("sessionId") || env.get("SENSOR_LAB_SESSION_ID") || "-";
var prev = flow.get("countdownTimer");
if (prev) { clearInterval(prev); }
flow.set("countdownActive", true);
var left = 10;
flow.set("countdownLeft", left);
node.send([null, {payload: "Countdown " + left + "..."}, {payload:{sessionId:sid, trialId:startMeta.trialId, activityLabel:startMeta.activityLabel, expectedType:startMeta.expectedType, recordingState:"countdown (" + left + "s)"}}]);
node.status({fill:"blue",shape:"ring",text:"Countdown "+left});
var t = setInterval(function () {
    left--;
    flow.set("countdownLeft", left);
    if (left > 0) {
        node.send([null, {payload: "Countdown " + left + "..."}, {payload:{sessionId:sid, trialId:startMeta.trialId, activityLabel:startMeta.activityLabel, expectedType:startMeta.expectedType, recordingState:"countdown (" + left + "s)"}}]);
        node.status({fill:"blue",shape:"ring",text:"Countdown "+left});
        return;
    }
    clearInterval(t);
    flow.set("countdownTimer", null);
    flow.set("countdownActive", false);
    flow.set("countdownLeft", null);
    node.send([{trialId:startMeta.trialId, activityLabel:startMeta.activityLabel, expectedType:startMeta.expectedType, note:startMeta.note}, {payload:"Recording: action — เริ่มทำท่าได้"}, {payload:{sessionId:sid, trialId:startMeta.trialId, activityLabel:startMeta.activityLabel, expectedType:startMeta.expectedType, recordingState:"recording"}}]);
    node.status({fill:"green",shape:"dot",text:"REC "+startMeta.trialId});
}, 1000);
flow.set("countdownTimer", t);
return null;

var rec = flow.get("recording") === true;
var cd = flow.get("countdownActive") === true;
var prev = flow.get("countdownTimer");
if (prev) { clearInterval(prev); flow.set("countdownTimer", null); }
flow.set("countdownActive", false);
flow.set("countdownLeft", null);
flow.set("recording", false);
var sid = flow.get("sessionId") || env.get("SENSOR_LAB_SESSION_ID") || "-";
var meta = flow.get("trialMeta") || {};
if (rec) {
    var done = flow.get("pendingSeq");
    if (done !== undefined && done !== null) {
        flow.set("trialSeq", done);
        flow.set("pendingSeq", null);
    }

    // Add to completed activities
    if (meta.activityLabel) {
        var completedActs = flow.get("completedActivities") || [];
        if (completedActs.indexOf(meta.activityLabel) === -1) {
            completedActs.push(meta.activityLabel);
            flow.set("completedActivities", completedActs);
        }
    }

    var nextSeq = (flow.get("trialSeq") || 0) + 1;
    var nextId = "T" + ("" + nextSeq).padStart(2, "0");
    var saved = sid + "_" + (meta.trialId || "T00") + "_" + (meta.activityLabel || "unknown") + ".csv";
    flow.set("lastSavedCsv", saved);
    node.status({fill:"grey",shape:"ring",text:"stopped, next "+nextId});
    return [
        {payload:"Session "+sid+" | Next Trial: "+nextId + " | ทำแล้ว " + (flow.get("completedActivities")||[]).length + " ท่า"},
        {payload:"Stopped / CSV saved"},
        {payload:{sessionId:sid, trialId:(meta.trialId || "-"), activityLabel:(meta.activityLabel || "-"), expectedType:(meta.expectedType || "-"), recordingState:"stopped", lastSavedCsv:saved}}
    ];
}
flow.set("pendingSeq", null);
var keepSeq = (flow.get("trialSeq") || 0) + 1;
var keepId = "T" + ("" + keepSeq).padStart(2, "0");
node.status({fill:"yellow",shape:"ring",text: cd ? "countdown cancelled" : "ready"});
return [
    {payload:"Session "+sid+" | Next Trial: "+keepId + " | ทำแล้ว " + (flow.get("completedActivities")||[]).length + " ท่า"},
    {payload: cd ? "Countdown cancelled — เลือกท่าใหม่ได้" : "Ready"},
    {payload:{sessionId:sid, trialId:(meta.trialId || keepId), activityLabel:(meta.activityLabel || "-"), expectedType:(meta.expectedType || "-"), recordingState:(cd ? "countdown_cancelled" : "ready"), lastSavedCsv:(flow.get("lastSavedCsv") || "-")}}
];

var s = msg.status || {};
var txt = s.text || "";
var fill = s.fill || "grey";
var connected = (fill === "green");
flow.set("mqttConnected", connected);
return {payload:{items:[{label:"MQTT", value:(connected ? "connected" : (txt || "disconnected")), color:(connected ? "green" : "red")}]}};

// แสดงค่า sensor ล่าสุด + ป้อนกราฟ (display-only ไม่ยุ่ง recording)
var p = msg.payload;
if (typeof p === "string") { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || typeof p !== "object") return null;
function n(v){ return (v === undefined || v === null || v === "") ? "-" : v; }
function d(v, dp, unit){ var x = Number.parseFloat(v); return Number.isFinite(x) ? x.toFixed(dp) + (unit || "") : "-"; }
function point(topic, value, dp){
    var x = Number.parseFloat(value);
    return Number.isFinite(x) ? {topic: topic, payload: Number(x.toFixed(dp))} : null;
}
flow.set("lastLabMsgTs", Date.now());
if (p.type === "imu_sample") flow.set("lastImuSampleTs", Date.now());
var live = { groups: [
    {title:"Acceleration", items:[{label:"AX", value:d(p.ax,3,"g")}, {label:"AY", value:d(p.ay,3,"g")}, {label:"AZ", value:d(p.az,3,"g")}]},
    {title:"Gyroscope", items:[{label:"GX", value:d(p.gx,2,"dps")}, {label:"GY", value:d(p.gy,2,"dps")}, {label:"GZ", value:d(p.gz,2,"dps")}]},
    {title:"Impact", items:[{label:"Magnitude (SVM)", value:d(p.svmFiltered,3,"g")}, {label:"Threshold", value:d(p.impactThreshold,3,"g")}]},
    {title:"Posture", items:[{label:"Pitch", value:d(p.pitch,2,"deg")}, {label:"Roll", value:d(p.roll,2,"deg")}, {label:"Delta", value:d(p.postureDelta,2,"deg")}, {label:"Threshold", value:d(p.postureThreshold,2,"deg")}]},
    {title:"Decision", items:[{label:"Type", value:n(p.type)}, {label:"State", value:n(p.state)}, {label:"Action", value:n(p.decision)}]}
]};
return [
    {payload: live},
    point("Magnitude (SVM)", p.svmFiltered, 3),
    point("Pitch", p.pitch, 2),
    point("Roll", p.roll, 2),
    point("Delta", p.postureDelta, 2),
    point("Impact Threshold", p.impactThreshold, 3),
    point("Posture Threshold", p.postureThreshold, 2),
    {payload: {items:[{label:"Device stream", value:"device/+/lab/imu ("+n(p.type)+")", color:"green"}]}},
    // กราฟ Acceleration (รวม 3 แกน: AX, AY, AZ)
    [point("AX", p.ax, 3), point("AY", p.ay, 3), point("AZ", p.az, 3)],
    // กราฟ Gyroscope (รวม 3 แกน: GX, GY, GZ)
    [point("GX", p.gx, 2), point("GY", p.gy, 2), point("GZ", p.gz, 2)]
];

// รวม System Status + Trial Metadata เป็น output เดียว (tick ทุก 1 วิ)
var now = Date.now();
var lab = flow.get("lastLabMsgTs");
var samp = flow.get("lastImuSampleTs");
var mq = flow.get("mqttConnected") === true;
var rec = flow.get("recording") === true;
var cd = flow.get("countdownActive") === true;
var left = flow.get("countdownLeft");
var meta = flow.get("trialMeta") || {};
var labAgo = lab ? (now - lab) : null;
var sampAgo = samp ? (now - samp) : null;
var dev = (labAgo === null || labAgo > 10000) ? "Offline" : (labAgo <= 3000 ? "Online" : "Stale");
var imuRecent = sampAgo !== null && sampAgo <= 3000;
var imu = imuRecent ? "recent" : (sampAgo === null ? "unknown" : "stale");
var warning = imuRecent ? "OK" : "Warning: No recent IMU sample";

var sid = meta.sessionId || flow.get("sessionId") || "-";
var nextId = "T" + ("" + ((flow.get("trialSeq") || 0) + 1)).padStart(2, "0");
var tid = meta.trialId || (sid !== "-" ? nextId : "-");
var activity = meta.activityLabel || "-";
var expected = meta.expectedType || "-";
var lastCsv = flow.get("lastSavedCsv") || "-";

// ดึงข้อมูลจำนวนท่าที่ทำเสร็จแล้ว
var completedActs = flow.get("completedActivities") || [];
var sidDisplay = sid;
if (sid !== "-" && completedActs.length > 0) {
    sidDisplay += " (เสร็จแล้ว " + completedActs.length + " ท่า)";
}

var state = rec ? "recording" : (cd ? ("countdown" + (left !== undefined && left !== null ? " (" + left + "s)" : "")) : (sid === "-" ? "wait_session" : "ready"));

function p2(x){ return ("" + x).padStart(2, "0"); }
function age(x){ return x === null ? "-" : Math.round(x / 1000) + "s"; }
function color(kind, value) {
    if (kind === "recording") return value === "recording" ? "blue" : (value === "countdown" ? "yellow" : (value === "wait_session" ? "gray" : "green"));
    if (value === true || value === "Online" || value === "recent" || value === "OK") return "green";
    if (value === "Stale" || value === "stale" || value === "countdown") return "yellow";
    if (value === false || value === "Offline" || value === "disconnected") return "red";
    return "gray";
}
var seen = "-";
if (labAgo !== null) {
    var dt = new Date(lab);
    seen = p2(dt.getHours()) + ":" + p2(dt.getMinutes()) + ":" + p2(dt.getSeconds());
}

var statusItems = [
    {label:"MQTT", value: mq ? "connected" : "disconnected", color: color("MQTT", mq)},
    {label:"Device", value: dev, color: color("Device", dev)}
];
if (dev === "Online" || dev === "Stale") {
    statusItems.push({label:"IMU", value: imu, color: color("IMU", imu)});
    if (warning !== "OK") {
        statusItems.push({label:"Warning", value: warning, color: "yellow"});
    }
}

var detailItems = [
    {label:"Last seen", value: seen},
    {label:"Last seen age", value: age(labAgo)},
    {label:"Current activity", value: activity},
    {label:"Current expected type", value: expected},
    {label:"Next trial ID", value: nextId},
    {label:"Topic", value: "device/+/lab/imu"}
];
var trialItems = [
    {label:"Session", value: sidDisplay},
    {label:"Trial", value: tid},
    {label:"Activity", value: activity},
    {label:"Expected", value: expected},
    {label:"State", value: state, color: color("recording", state)},
    {label:"Last CSV", value: lastCsv}
];
node.status({fill: dev === "Online" ? "green" : (dev === "Stale" ? "yellow" : "red"), shape: "dot", text: dev});
return {payload: {statusItems: statusItems, detailItems: detailItems, trialItems: trialItems, items: statusItems.concat(detailItems)}};

// แสดงค่า default หลัง deploy โดยไม่เปลี่ยน trial/save state
return [
  {payload:{lastSavedCsv:"-"}},
  {payload:{groups:[
    {title:"Acceleration", items:[{label:"AX", value:"-"}, {label:"AY", value:"-"}, {label:"AZ", value:"-"}]},
    {title:"Gyroscope", items:[{label:"GX", value:"-"}, {label:"GY", value:"-"}, {label:"GZ", value:"-"}]},
    {title:"Impact", items:[{label:"Magnitude (SVM)", value:"-"}, {label:"Threshold", value:"-"}]},
    {title:"Posture", items:[{label:"Pitch", value:"-"}, {label:"Roll", value:"-"}, {label:"Delta", value:"-"}, {label:"Threshold", value:"-"}]},
    {title:"Decision", items:[{label:"Type", value:"-"}, {label:"State", value:"-"}, {label:"Action", value:"-"}]}
]}}
];

var now = Date.now();
var last = context.get("lastLogTs") || 0;
// Only pass 1 message per second to prevent browser lag
if (now - last >= 1000) {
    context.set("lastLogTs", now);
    return msg;
}
return null;

// อ่านโฟลเดอร์ /data/runs/ แล้วส่งรายการ session ที่มีอยู่
// fsMod มาจาก functionExternalModules (require('fs'))
var runsDir = flow.get('runsDir') || '/data/runs';
var options = [];
try {
    var dirs = fsMod.readdirSync(runsDir);
    dirs.filter(function(d) {
        try { return fsMod.statSync(runsDir + '/' + d).isDirectory(); }
        catch(e) { return false; }
    }).sort().reverse().forEach(function(d) {
        options.push({ value: d, label: d });
    });
} catch(e) {
    node.warn('scan sessions error: ' + e.message);
}
